import os
import subprocess

def extract_tar(file_path, dest_dir):
    if not os.path.exists(dest_dir):
        os.makedirs(dest_dir)

    cmd = ['tar', '-xvf', file_path]
    try:
        subprocess.run(cmd, cwd=dest_dir)
    except Exception as e:
        print(f"Error extracting tar: {e}")